import React, { useState, useEffect } from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  Legend,
  ResponsiveContainer
} from "recharts";

function Prediction() {

  const [distance, setDistance] = useState("");
  const [temperature, setTemperature] = useState("");
  const [prediction, setPrediction] = useState(null);
  const [history, setHistory] = useState([]);
  const [sensorData, setSensorData] = useState([]);

  // -----------------------------
  // Manual Prediction
  // -----------------------------
  const predict = async () => {

    const res = await fetch("http://127.0.0.1:8000/api/v1/predict", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        distance: Number(distance),
        temperature: Number(temperature)
      })
    });

    const data = await res.json();
    setPrediction(data);

    loadHistory();
  };

  // -----------------------------
  // Load history
  // -----------------------------
  const loadHistory = async () => {

    const res = await fetch("http://127.0.0.1:8000/api/v1/history");
    const data = await res.json();

    setHistory(data);
  };

  // -----------------------------
  // Auto sensor data
  // -----------------------------
  const loadSensor = async () => {

    const res = await fetch("http://127.0.0.1:8000/api/v1/auto-predict");
    const data = await res.json();

    setSensorData(prev => [
      ...prev.slice(-9),
      {
        time: data.time,
        distance: data.distance,
        temperature: data.temperature
      }
    ]);

    setPrediction(data);

    loadHistory();
  };

  useEffect(() => {

    loadHistory();
    loadSensor();

    const interval = setInterval(() => {
      loadSensor();
    }, 5000);

    return () => clearInterval(interval);

  }, []);

  return (
    <div style={{ padding: "20px" }}>

      <h1>Water Activity Prediction</h1>

      <input
        type="number"
        placeholder="Distance"
        value={distance}
        onChange={(e) => setDistance(e.target.value)}
      />

      <input
        type="number"
        placeholder="Temperature"
        value={temperature}
        onChange={(e) => setTemperature(e.target.value)}
      />

      <button onClick={predict}>Predict</button>

      {prediction && (
        <div style={{ marginTop: "20px" }}>
          <h3>Prediction Result</h3>

          <p>Activity: {prediction.prediction}</p>
          <p>Confidence: {prediction.confidence}</p>

          <h3>Tank Status</h3>

          <p>Water Level: {prediction.water_level} cm</p>
          <p>Water Volume: {prediction.volume_liters} Liters</p>
        </div>
      )}

      <h2 style={{ marginTop: "40px" }}>Real Time Sensor Graph</h2>

      <ResponsiveContainer width="100%" height={300}>
        <LineChart data={sensorData}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="time" />
          <YAxis />
          <Tooltip />
          <Legend />
          <Line type="monotone" dataKey="distance" stroke="#8884d8" />
          <Line type="monotone" dataKey="temperature" stroke="#82ca9d" />
        </LineChart>
      </ResponsiveContainer>

      <h2 style={{ marginTop: "40px" }}>Prediction History</h2>

      <table border="1" cellPadding="10">
        <thead>
          <tr>
            <th>Time</th>
            <th>Distance</th>
            <th>Temperature</th>
            <th>Prediction</th>
            <th>Confidence</th>
          </tr>
        </thead>

        <tbody>
          {history.map((item, index) => (
            <tr key={index}>
              <td>{item.time}</td>
              <td>{item.distance}</td>
              <td>{item.temperature}</td>
              <td>{item.prediction}</td>
              <td>{item.confidence}</td>
            </tr>
          ))}
        </tbody>
      </table>

    </div>
  );
}

export default Prediction;
